-- Migra o changelog do array estático em src/lib/changelog.ts para o banco —
-- necessário pro fluxo "Ativar pra todas" (Novas Features) publicar a novidade
-- na hora, sem precisar de deploy novo pra cada entrada.

CREATE TABLE IF NOT EXISTS changelog_entries (
  id text PRIMARY KEY,
  version text NOT NULL UNIQUE,
  entry_date date NOT NULL,
  items jsonb NOT NULL,
  feature_flag_id text REFERENCES feature_flags(id) ON DELETE SET NULL,
  created_at timestamp NOT NULL DEFAULT now(),
  updated_at timestamp NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS changelog_entries_entry_date_idx ON changelog_entries (entry_date DESC);

-- Seed com o histórico existente (gerado a partir do array estático em
-- src/lib/changelog.ts, que é removido depois desta migration).
